#!/usr/bin/env python3
"""vocab-shard-lmhead - split the lm-head (vocab projection) across nodes.

The lm-head dominates DECODE latency (~188ms on an R1): a memory-bound matmul of
the residual against the full 144MB tied-embedding over the 151,936-token vocab.
It runs on ONE node. This splits the vocab range across N nodes in PARALLEL via
fat-station's X-Vocab-Start/X-Vocab-End headers (kernel: lm_head_range), then
merges the per-shard argmax -> ~1/N the lm-head wall-clock.

  residual --+--> /lm-head X-Vocab 0..V/2      (node A)  --+
             +--> /lm-head X-Vocab V/2..V       (node B)  --+--> merge argmax

Compares single-node lm-head vs sharded, and checks the merged argmax matches.
Endpoints/env identical to mesh-shootout.py. The residual is produced once (full
forward on the embed node) so this isolates the lm-head cost.

Usage: python3 vocab-shard-lmhead.py [--runs N] [--layers L] [--vocab V]
"""
import argparse, os, struct, sys, time, urllib.request, urllib.error, statistics
from concurrent.futures import ThreadPoolExecutor

MAC = os.environ.get("MESH_MAC", "http://127.0.0.1:8080")
R1A = os.environ.get("MESH_R1A", "http://127.0.0.1:8090")
R1B = os.environ.get("MESH_R1B", "http://127.0.0.1:8091")


def post(base, path, body, headers):
    req = urllib.request.Request(base + path, data=body, method="POST")
    for k, v in headers.items():
        req.add_header(k, v)
    with urllib.request.urlopen(req, timeout=300) as r:
        return r.read()


def up(base):
    try:
        urllib.request.urlopen(base + "/health", timeout=4).read(); return True
    except (urllib.error.URLError, OSError):
        return False


to_f32 = lambda b: struct.unpack("<%df" % (len(b) // 4), b)


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("--runs", type=int, default=7)
    ap.add_argument("--layers", type=int, default=24)
    ap.add_argument("--vocab", type=int, default=151936)
    ap.add_argument("--tokens", default="785,6722,315,9625,374")
    ap.add_argument("--expect", type=int, default=12095)
    args = ap.parse_args()
    tokens = [int(x) for x in args.tokens.split(",")]
    seq = len(tokens)

    shards = [b for b in (R1A, R1B) if up(b)]
    head = R1A if up(R1A) else (MAC if up(MAC) else None)
    embed = MAC if up(MAC) else head
    if not head or len(shards) < 2:
        print("need >=2 R1 stations up for vocab sharding", file=sys.stderr); return 2

    # produce the residual once (full forward on the embed node)
    buf = post(embed, "/embed", struct.pack("<%dI" % seq, *tokens), {"X-Position": "0"})
    residual = post(embed, "/forward", buf,
                    {"X-Position": "0", "X-Sequence-Length": str(seq), "X-Layer-Range": f"0-{args.layers}"})

    def single():
        t0 = time.time()
        lg = to_f32(post(head, "/lm-head", residual, {"X-Sequence-Length": str(seq)}))
        return (time.time() - t0) * 1000, max(range(len(lg)), key=lambda i: lg[i])

    def sharded():
        n = len(shards)
        bounds = [(i * args.vocab // n, (i + 1) * args.vocab // n) for i in range(n)]
        t0 = time.time()
        def one(k):
            vs, ve = bounds[k]
            lg = to_f32(post(shards[k], "/lm-head", residual,
                             {"X-Sequence-Length": str(seq), "X-Vocab-Start": str(vs), "X-Vocab-End": str(ve)}))
            j = max(range(len(lg)), key=lambda i: lg[i])
            return lg[j], vs + j  # (best logit, global token id)
        with ThreadPoolExecutor(max_workers=n) as ex:
            parts = list(ex.map(one, range(n)))
        best = max(parts, key=lambda p: p[0])
        return (time.time() - t0) * 1000, best[1]

    # warm
    single(); sharded()
    s_t, s_a = [], None
    p_t, p_a = [], None
    for _ in range(args.runs):
        t, a = single(); s_t.append(t); s_a = a
        t, a = sharded(); p_t.append(t); p_a = a
    sm, pm = statistics.median(s_t), statistics.median(p_t)
    print(f"residual: {len(residual)//4} f32  shards: {len(shards)}  vocab: {args.vocab}\n")
    print(f"{'lm-head config':<34} {'ms':>7} {'argmax':>8}")
    print("-" * 52)
    print(f"{'single-node (full vocab)':<34} {sm:>7.1f} {s_a:>8} {'OK' if s_a==args.expect else 'WRONG'}")
    print(f"{f'{len(shards)}-way vocab-shard (parallel)':<34} {pm:>7.1f} {p_a:>8} {'OK' if p_a==args.expect else 'WRONG'}")
    print(f"\nspeedup: {sm/pm:.2f}x   merged argmax {'MATCHES' if p_a==s_a else 'DIFFERS from'} single-node")
    return 0 if (p_a == args.expect and s_a == args.expect) else 1


if __name__ == "__main__":
    sys.exit(main())
